SELECT c.comment_id, c.card_id, c.user_id, COALESCE(c.user_nickname, u.nickname, u.username) AS user_nickname, c.content, c.rating, c.comment_type, c.status, c.admin_reply, c.feedback_id, c.is_note, c.like_count, c.dislike_count, c.reply_count, c.create_time, c.update_time, card.front_content AS card_front_content, sub.subject_name, CASE c.comment_type WHEN 'QUALITY' THEN '优质内容' WHEN 'POOR' THEN '劣质内容' ELSE '中性评价' END AS comment_type_text, CASE c.status WHEN '0' THEN '正常' WHEN '1' THEN '已处理' WHEN '2' THEN '已隐藏' ELSE '未知' END AS status_text
, COALESCE(cl.like_type, 0) AS like_status
FROM biz_card_comment c LEFT JOIN sys_user u ON c.user_id = u.user_id LEFT JOIN biz_card card ON c.card_id = card.card_id LEFT JOIN biz_subject sub ON card.subject_id = sub.subject_id
LEFT JOIN biz_comment_like cl ON c.comment_id = cl.comment_id AND cl.user_id = #{userId}
AND c.card_id = #{cardId}
AND c.comment_type = #{commentType}
AND c.status = #{status}
ORDER BY c.like_count DESC, c.reply_count DESC, c.create_time DESC

SELECT c.comment_id, c.card_id, c.user_id, COALESCE(c.user_nickname, u.nickname, u.username) AS user_nickname, c.content, c.rating, c.like_count, c.reply_count, c.create_time, c.update_time, card.front_content AS card_front_content, sub.subject_name FROM biz_card_comment c LEFT JOIN sys_user u ON c.user_id = u.user_id INNER JOIN biz_card card ON c.card_id = card.card_id AND card.del_flag = '0' LEFT JOIN biz_subject sub ON card.subject_id = sub.subject_id WHERE c.is_note = 1 AND c.status = '0'
AND c.user_id = #{userId}
AND c.user_id IN ( SELECT user_id FROM sys_user WHERE nickname LIKE CONCAT('%', #{username}, '%') OR username LIKE CONCAT('%', #{username}, '%') )
AND card.subject_id = #{subjectId}
AND c.card_id = #{cardId}
AND c.create_time >= CONCAT(#{startDate}, ' 00:00:00')
AND c.create_time < CONCAT(#{endDate}, ' 23:59:59')
AND (c.content LIKE CONCAT('%', #{keyword}, '%') OR card.front_content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY c.comment_id ASC
